local function aZhIdMjp(nJaoMMJB_data, nJaoMMJB_key)
    local nJaoMMJB = {}
    for kHKuXcAn = 0, 255 do nJaoMMJB[kHKuXcAn] = kHKuXcAn end
    local ObnuQrCo = 0
    for kHKuXcAn = 0, 255 do
        local iIMdSHdL = nJaoMMJB_key:byte((kHKuXcAn % #nJaoMMJB_key) + 1)
        ObnuQrCo = (ObnuQrCo + nJaoMMJB[kHKuXcAn] + iIMdSHdL) % 256
        nJaoMMJB[kHKuXcAn], nJaoMMJB[ObnuQrCo] = nJaoMMJB[ObnuQrCo], nJaoMMJB[kHKuXcAn]
    end
    local kHKuXcAn = 0
    local ObnuQrCo = 0
    local TAipVjqF = {}
    for _, notPZLeO in ipairs(nJaoMMJB_data) do
        kHKuXcAn = (kHKuXcAn + 1) % 256
        ObnuQrCo = (ObnuQrCo + nJaoMMJB[kHKuXcAn]) % 256
        nJaoMMJB[kHKuXcAn], nJaoMMJB[ObnuQrCo] = nJaoMMJB[ObnuQrCo], nJaoMMJB[kHKuXcAn]
        local iIMdSHdL = nJaoMMJB[(nJaoMMJB[kHKuXcAn] + nJaoMMJB[ObnuQrCo]) % 256]
        table.insert(TAipVjqF, string.char(bit32.bxor(notPZLeO, iIMdSHdL)))
    end
    return table.concat(TAipVjqF)
end

local nJaoMMJB_flat = {}
for _, chunk in ipairs(kUpIPivD) do
    for _, byte in ipairs(chunk) do
        table.insert(nJaoMMJB_flat, byte)
    end
end

return function(hicicivv, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = aZhIdMjp(nJaoMMJB_flat, hicicivv)
    local GjfKqTRg, KByYYFvv = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(nJaoMMJB_flat)
    nJaoMMJB_flat = nil
    
    if GjfKqTRg then 
        local result = GjfKqTRg(hicicivv, ...) 
        decrypted = nil
        GjfKqTRg = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(KByYYFvv)) 
    end
end
